---@type BaseIconNew
local BaseIconNew = LXImport(".BaseIconNew")
------------------------------------------------------------------
---@class FishIconNew:BaseIconNew
local FishIconNew = LxClass("FishIconNew", BaseIconNew)
-----------------------------------------------------------------

function FishIconNew:FishIconNew(wndClass)
	self._refId = 0
	self._num = nil
	self._showNum = false

	self._isNativeSize = false
    self._displayShowIcon = nil
	self._displayShowIconBg = nil

end

function FishIconNew:OnDestroy()

end

-----------------------------------------------------------------
---
function FishIconNew:ResetIcon()
	BaseIconNew.ResetIcon(self)

	self._refId = 0
	self._num = nil
	self._showNum = false
	self._showOver = false
end

-----------------------------------------------------------------
function FishIconNew:ApplyIconUI()
	BaseIconNew.ApplyIconUI(self)

	self:SetIcon(self._displayShowIcon)
	self:SetIconBg(self._displayShowIconBg)

	self:SetNumUIVisible()
	self:ApplyLvTxt()
	self:SetOverUIVisible()
end

function FishIconNew:OnInitTrans()
	local iconInst = self._iconInst
	self._uiNumTxtTrans = CS.FindTrans(iconInst,"NumTxt")
	self._uiOverTrans = CS.FindTrans(iconInst,"Over")
end

-----------------------------------------------------------------
function FishIconNew:EnableShowNum(bShow)
	self._showNum = bShow
	self:UpdateNumData()
end

function FishIconNew:EnableShowOver(bShow)
	self._showOver = bShow
	self:SetOverUIVisible()
end

function FishIconNew:ShowNum(b)
	self._showNum = b

	self:UpdateNumData()

	if not self:IsIconValid() then return end

	self:SetNumUIVisible()

end

function FishIconNew:UpdateNumData()
	if self._showNum and not self._num then
		self._displayNum = 0
		return
	end
	self._displayNum = self._num or 0
end

function FishIconNew:SetNumUIVisible()
	local b = self._showNum and self._showNum or false

	if self._uiNumTxtTrans.gameObject.activeSelf ~= b then
		CS.ShowObject(self._uiNumTxtTrans, b)
	end
end

function FishIconNew:SetOverUIVisible()
	local b = self._showOver and self._showOver or false

	if self._uiOverTrans and self._uiOverTrans.gameObject.activeSelf ~= b then
		CS.ShowObject(self._uiOverTrans, b)
	end
end

function FishIconNew:ApplyLvTxt()
	if not self._showNum then return end
	local num = self._displayNum
	local numStr = tostring(num)
	if not num or num == -1 then
		numStr = ""
	end
	self:SetXUIText(self._uiNumTxtTrans,numStr)
end


function FishIconNew:SetItemNum(num)
	self._num = num

	self:UpdateNumData()

	if not self:IsIconValid() then return end
	self:ApplyLvTxt()
end

-----------------------------------------------------------------
function FishIconNew:SetData(refId, itemNum)
	self._refId = refId
	self._num = itemNum
	local ref = self:GetRef(refId)
	local iconPath = nil
	local iconBgPath = nil
    local itemColor = nil

	if ref then
		iconPath = ref.icon
		local quality = ref.quality
		local qualityRef = self:GetItemQualityRef(quality)
		if qualityRef then
			iconBgPath = qualityRef.iconBg
			local color = qualityRef.nameColor
			if color then
				itemColor = LUtil.ColorByHex(color)
			end
		end
	else
		self._showNum = false
		iconPath = "pet_icon_off"
		iconBgPath = "public_item_bg_1"
	end

	self._displayShowIcon = iconPath
	self._displayShowIconBg = iconBgPath

	self:UpdateNumData()
end


-----------------------------------------------------------------
function FishIconNew:GetRef(refId)
	return GameTable.FishingArticleRef[refId]
end

-----------------------------------------------------------------
return FishIconNew